const items = $input.all();
const toProcess = [];
for (const item of items) {
  const data = item.json;
  const results = data.results || [data];
  for (const d of results) {
    const sent = d.properties?.satisfaction_envoyee;
    if (!sent || sent === 'false') {
      toProcess.push({ json: {
        dealId: d.id,
        dealName: d.properties?.dealname || '',
        type_fuite: d.properties?.type_fuite || 'fuite',
        ville_intervention: d.properties?.ville_intervention || '',
        technicien: d.properties?.technicien || ''
      }});
    }
  }
}
if (toProcess.length === 0) return [];
return toProcess;

const deal = $('Code JS - Filtrer deals sans satisfaction' in $items ? $('Code JS - Filtrer deals sans satisfaction') : $('[CODE JS] - Filtrer deals sans satisfaction')).item?.json
  || $('[CODE JS] - Filtrer deals sans satisfaction').item?.json;
// Use previous node reference safely
const prevDeal = $('[HUBSPOT] - Marquer satisfaction_envoyee = true').item?.json || {};
const dealId = prevDeal.dealId || '';
const dealName = prevDeal.dealName || '';
const type_fuite = prevDeal.type_fuite || 'fuite';
const ville = prevDeal.ville_intervention || '';
const technicien = prevDeal.technicien || '';

const assocData = $input.first().json;
const contacts = assocData?.results || [];
if (contacts.length === 0) {
  return [{ json: { dealId, dealName, type_fuite, ville_intervention: ville, technicien, contactId: null, hasContact: false }}];
}
return [{ json: {
  dealId, dealName, type_fuite, ville_intervention: ville, technicien,
  contactId: contacts[0].id,
  hasContact: true
}}];

const contactRaw = $input.first().json.properties || {};
const dealNode = $('[CODE JS] - Extraire contactId').item.json;

const prenom = contactRaw.firstname || 'cher client';
const email = contactRaw.email || '';
const company = contactRaw.company || '';

// Déduire type_client
let type_client = (contactRaw.type_client || '').toLowerCase().trim();
if (!type_client) {
  type_client = company ? 'inconnu' : 'particulier';
}

// Format phone pour WhatsApp
let phone = contactRaw.phone || '';
let tel = phone.replace(/[\s\-\.\(\)\/]/g, '');
if (tel.startsWith('0')) tel = '33' + tel.slice(1);
if (tel && !tel.startsWith('+')) tel = '+' + tel;

return [{json: {
  dealId:            dealNode.dealId,
  dealName:          dealNode.dealName,
  type_fuite:        dealNode.type_fuite,
  ville_intervention:dealNode.ville_intervention,
  technicien:        dealNode.technicien,
  contactId:         dealNode.contactId,
  prenom,
  email,
  phone: tel,
  hasPhone:  !!tel,
  hasEmail:  !!email,
  type_client,
  company
}}];

const staticData = $getWorkflowStaticData('global');
if (!staticData.attente_nps) staticData.attente_nps = {};

const d = $json;
const telephone = d.phone || '';

if (telephone) {
  staticData.attente_nps[telephone] = {
    contactId:         d.contactId,
    dealId:            d.dealId,
    prenom:            d.prenom,
    email:             d.email,
    type_fuite:        d.type_fuite,
    ville_intervention:d.ville_intervention,
    timestamp:         Date.now()
  };
}
return [$input.first()];

