const staticData = $getWorkflowStaticData('global');
const body = $input.first().json.body || $input.first().json;

// Extract WhatsApp message info
let fromTel = '';
let messageText = '';
let messageType = '';

try {
  const changes = body?.entry?.[0]?.changes?.[0]?.value;
  const messages = changes?.messages;
  if (messages && messages.length > 0) {
    fromTel = messages[0].from || '';
    messageType = messages[0].type || '';
    if (messageType === 'text') {
      messageText = messages[0].text?.body || '';
    }
  }
} catch(e) {}

// Format phone to E.164
let fromFormatted = fromTel;
if (fromFormatted && !fromFormatted.startsWith('+')) {
  fromFormatted = '+' + fromFormatted;
}

// Check if in attente_nps
const attente = staticData.attente_nps || {};
const npsData = attente[fromFormatted] || attente[fromTel] || null;
const isNPS = !!npsData;

return [{json: {
  isNPS,
  fromTel: fromFormatted || fromTel,
  messageText,
  messageType,
  npsData,
  originalBody: body
}}];

const d = $json;
const text = (d.messageText || '').trim();
const score = parseInt(text, 10);
const isValid = !isNaN(score) && score >= 0 && score <= 10;

return [{json: {
  isNPS:       d.isNPS,
  fromTel:     d.fromTel,
  messageText: d.messageText,
  score:       isValid ? score : -1,
  isValid,
  npsData:     d.npsData
}}];

